Code.Terraform:
```hcl
# Terraform: WAFv2 Web ACL ルールで CloudWatch メトリクスを有効にする
resource "aws_wafv2_web_acl" "<example_resource_name>" {
  name  = "<example_resource_name>"
  scope = "REGIONAL"

  default_action { allow {} }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "<metric_name>"
    sampled_requests_enabled   = true
  }

  rule {
    name     = "<example_rule_name>"
    priority = 1

    statement {
      managed_rule_group_statement {
        vendor_name = "AWS"
        name        = "AWSManagedRulesCommonRuleSet"
      }
    }

    override_action { none {} }

    visibility_config {
      cloudwatch_metrics_enabled = true  # 重要: このルールのCloudWatchメトリクスを有効にします
      metric_name                = "<rule_metric_name>"  # CloudWatch メトリクスで必須
      sampled_requests_enabled   = true
    }
  }
}
```
